// ── Helper functions ──────────────────────────────────────────────────
export function getYogaPada(padaId: string): YogaPada | undefined {
  return yogaPadas.find((p) => p.id === padaId)
}

export function getYogaPadaByNumber(num: number): YogaPada | undefined {
  return yogaPadas.find((p) => p.number === num)
}

export function getYogaSutra(id: string): YogaSutraVerse | undefined {
  return allYogaSutraVerses.find((v) => v.id === id)
}

